#include <gtest/gtest.h>
#include <solvers/fish.h>

TEST(Test2Fish, XWing1) {
    // #X-Wing: 2 r38 c34 => r1c34,r2c3<>2
    Inst inst = {
        0x20,                               // type
        0x2F, 0x7F, 0xF2, 0xF3,             // hint
        1,                                  // target
        0x02, 0x01, 0x03, 0x01, 0x12, 0x01  // executees
    };
    std::vector<uint16_t> executees = {0x0201, 0x0301, 0x1201};
    Grid grid(
        "0001001000000100000000000001101000100001100100001800000000001700000000"
        "0000011001000000001100001000000101001000011000001018000000000000011000"
        "1010150000000000000011000000000101010000001110010000000010001010001000"
        "0110001600000000000400000000000001100010000001100000001100000000001900"
        "0000000015000000000000001000110000000000110000000100001012000000000006"
        "0000000000070000000000150000000000080000000000000001000010110000000000"
        "1300000000000100000000001500000000001800000000000000100100100000110000"
        "0000000101000017000000000012000000000000000100001017000000000013000000"
        "0000000001000010001000000010120000000000001001000000080000000000160000"
        "0000000500000000000000110000000000000110001100000000001800000000001900"
        "0000000005000000000000001101000000001100100012000000000000000100010000"
        "0000001010000101000000001100000000060000000000130000000000001000000010"
        "1500000000000010010011100001101001000000000100100000101000001400000000"
        "00170000000000001100000000001010010010000010000110001000010110");
    findFish(grid, 2);
    EXPECT_EQ(*grid.getInst(), inst);
    EXPECT_EQ(grid.getExec()->mode, false);
    EXPECT_EQ(grid.getExec()->executees, executees);
}

